-- ============================================================

-- 1. Property Maintenance × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'web-design',
  'Property maintenance companies offer one of the broadest service ranges in the trades sector, from emergency plumbing repairs and electrical fault-finding to planned kitchen refurbishments, painting programmes, and garden maintenance contracts. Your website must communicate this breadth without overwhelming visitors or diluting the impression that you are competent in any single discipline. When a letting agent needs an emergency boiler repair at seven in the evening, they need to find your emergency number instantly. When a homeowner is planning a bathroom renovation, they want to see examples of similar completed work and understand your process. When a facilities manager is evaluating maintenance contractors for a portfolio of commercial properties, they need to see contract capability, compliance credentials, and multi-trade capacity. Most property maintenance websites are cluttered pages listing dozens of services with no structure, no clear emergency pathway, and no distinction between reactive repairs and planned maintenance programmes. We build websites that organise your full service range into clear categories, provide instant emergency contact for urgent repairs, showcase completed projects across every discipline, and present contract maintenance packages for landlords, letting agents, and commercial property managers.',
  'Property maintenance businesses live and die by their ability to be found quickly when something breaks. A burst pipe, a boiler failure in January, or a broken window at a rental property all generate urgent searches where the first credible company found gets the call. Beyond emergencies, planned maintenance contracts with letting agents and property managers represent your most stable revenue stream, and these clients evaluate your website as part of their due diligence before awarding contracts. A professional website that handles both audiences wins work on both fronts.',
  'We organise your website around how customers actually search: emergency repairs with instant contact, planned maintenance services with project galleries, and contract packages for property professionals. Emergency banners with click-to-call functionality sit above the fold on mobile. Service pages are grouped by trade discipline rather than presented as an overwhelming alphabetical list.',
  '[{"title": "Service range too broad to present clearly on one website", "description": "Property maintenance companies often list thirty or more individual services on a single page, from tap washer replacements to full kitchen installations. This overwhelming approach means visitors cannot quickly find the specific service they need, and the business appears to be a jack-of-all-trades with no particular expertise in any area."}, {"title": "Emergency callers unable to distinguish you from planned-work-only companies", "description": "When a letting agent has a tenant reporting a gas leak or a burst pipe, they need to know within seconds that you handle emergencies and that you are available now. If your website presents emergency repairs and planned bathroom renovations identically, urgent callers cannot tell whether you offer the rapid response they desperately need."}, {"title": "No dedicated pathway for contract and commercial clients", "description": "Letting agents, property managers, and facilities managers evaluating maintenance contractors need to see contract capability, response time guarantees, multi-trade capacity, and compliance credentials. When they land on a website designed entirely for domestic homeowners, they assume you cannot handle the scale and professionalism their portfolio demands."}]',
  '[{"title": "Structured service architecture across all trade disciplines", "description": "Your full service range organised into clear categories: plumbing, electrical, carpentry, decorating, roofing, garden maintenance, and general repairs. Each category has its own landing page with service descriptions, project galleries, and relevant credentials. Visitors find exactly what they need without wading through irrelevant services."}, {"title": "Emergency-first design with instant reactive repair contact", "description": "A persistent emergency banner with click-to-call functionality visible on every page without scrolling. After-hours visitors see your emergency availability status and response time commitment. This captures the urgent reactive repair work that generates premium call-out charges and often leads to larger follow-on projects."}, {"title": "Contract client portal and property professional landing pages", "description": "Dedicated sections for letting agents, property managers, and commercial clients presenting your contract maintenance packages, response time SLAs, compliance documentation, and multi-property management capability. Optional client portal integration allows contract clients to log maintenance requests and track job progress online."}]',
  '[{"question": "How do you organise so many different services on one website?", "answer": "We group your services into logical trade categories that match how customers search. Plumbing, electrical, carpentry, decorating, roofing, and general repairs each have dedicated sections with their own landing pages. Within each category, individual services are listed with descriptions, pricing guidance, and relevant project photos."}, {"question": "Can the website handle both emergency callouts and planned project enquiries?", "answer": "Yes. We build separate pathways for emergency and planned work. Emergency visitors see a prominent click-to-call banner on every page with your response time commitment. Planned work visitors navigate to the relevant service category, view project galleries, and submit detailed enquiry forms that capture the information you need to quote accurately."}, {"question": "How do you attract letting agent and property management clients through the website?", "answer": "Dedicated landing pages address the specific concerns of property professionals: response time guarantees, multi-trade capability, compliance documentation, tenant communication protocols, and contract pricing structures. These pages target searches like property maintenance contractor for letting agents and rank for the terms property professionals actually use."}, {"question": "Should I include pricing on my property maintenance website?", "answer": "We recommend including indicative pricing or price ranges for common services like boiler servicing, emergency call-out charges, and standard repair rates. Property professionals evaluating contractors particularly appreciate transparent pricing. Bespoke project work can be quoted individually, but showing standard rates builds trust and filters enquiries to customers comfortable with your pricing."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Property Maintenance × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'seo',
  'Property maintenance companies have one of the largest keyword opportunities in local search because the sheer breadth of services creates hundreds of targetable search terms. Every trade discipline you cover generates its own cluster of searches: emergency plumber near me, handyman for kitchen fitting, property maintenance company for landlords, commercial building maintenance contractor, and dozens more. Yet most property maintenance websites attempt to rank for everything with a single homepage and a generic services page, which means they rank well for nothing. The companies dominating local search in this sector have dedicated, optimised pages for every service category, every customer type, and every emergency scenario. Our SEO campaigns for property maintenance businesses exploit the full width of your service offering, building targeted content around each trade discipline, each customer segment, and the seasonal patterns that drive maintenance demand throughout the year. From emergency plumbing searches in frozen January pipes to end-of-tenancy property renovation searches in summer, we ensure your business captures traffic across every service and every season.',
  'Property maintenance work splits between reactive emergency repairs and planned maintenance contracts, and both begin with search. Emergency searches convert immediately and at premium rates. Planned maintenance and contract searches from letting agents and property managers represent long-term recurring revenue. Without an SEO strategy that targets both, you are invisible for the most valuable searches in your sector and reliant on word of mouth that cannot scale your business beyond its current capacity.',
  'We build SEO campaigns around the multi-trade nature of property maintenance. Individual service pages target specific trade searches while category pages capture broader maintenance queries. Seasonal content strategies anticipate demand peaks: frozen pipe emergencies in winter, garden maintenance in spring, painting programmes in summer, and boiler servicing in autumn.',
  '[{"title": "Ranking for nothing because you target everything simultaneously", "description": "A single services page listing plumbing, electrical, carpentry, decorating, roofing, and garden maintenance cannot rank well for any individual service search. Google sees a page trying to cover thirty topics and ranks it below specialists who dedicate entire pages to each service. Your breadth, which should be an advantage, becomes an SEO weakness."}, {"title": "Invisible for emergency property repair searches", "description": "Emergency property maintenance searches like emergency plumber letting agent, burst pipe property maintenance, and emergency boiler repair landlord have extremely high conversion rates. Without dedicated emergency pages optimised for these urgent queries, you are invisible at the exact moment when letting agents and property managers are desperate to find you."}, {"title": "Missing seasonal demand peaks throughout the year", "description": "Property maintenance demand follows predictable seasonal patterns, yet most companies make no effort to capture seasonal search traffic. Frozen pipe searches spike in December and January. Garden maintenance peaks in March and April. Exterior painting searches rise in May and June. Without seasonal content, you miss these predictable surges in demand."}]',
  '[{"title": "Service-specific landing pages for every trade discipline", "description": "Individual optimised pages for plumbing, electrical, carpentry, decorating, roofing, garden maintenance, kitchen fitting, bathroom renovation, and every other service you offer. Each page targets the specific search terms customers use for that service, creating dozens of ranking opportunities from a single website."}, {"title": "Emergency repair SEO with rapid-response schema markup", "description": "Dedicated emergency pages targeting urgent property repair searches with structured data declaring 24/7 availability, emergency response times, and service area coverage. Google Business Profile optimisation ensures Map Pack visibility for after-hours searches when letting agents and homeowners need immediate help."}, {"title": "Seasonal content strategy capturing year-round demand", "description": "A twelve-month content calendar aligned with property maintenance demand patterns. Winter content targets frozen pipes, boiler emergencies, and storm damage. Spring covers garden clearance and exterior preparation. Summer focuses on decorating, renovations, and planned maintenance. Autumn targets boiler servicing and weatherproofing. Every season drives relevant traffic to your site."}]',
  '[{"question": "How do you handle SEO for a company that offers so many different services?", "answer": "Breadth is actually an SEO advantage when handled correctly. We create dedicated landing pages for each service category, each targeting its own keyword cluster. A property maintenance company with pages for plumbing, electrical, carpentry, decorating, roofing, and garden services has six times more ranking opportunities than a specialist with just one service."}, {"question": "Can we rank for emergency property maintenance searches?", "answer": "Yes. Emergency pages with specific schema markup for 24/7 availability and rapid response perform well in local search. We target the exact terms letting agents and property managers use during emergencies, including landlord-specific variants. Google Business Profile optimisation ensures you appear in the Map Pack for urgent after-hours searches."}, {"question": "How important are letting agent and landlord-specific keywords?", "answer": "Extremely. Property professionals searching for maintenance contractors use different terms than domestic homeowners. Searches like property maintenance for letting agents, landlord handyman service, and contract maintenance company represent high-value recurring revenue. We create dedicated content targeting these commercial keywords alongside domestic search terms."}, {"question": "How long before SEO starts generating leads for a property maintenance company?", "answer": "Google Business Profile improvements can increase Map Pack visibility within four to six weeks. Individual service pages typically begin ranking within two to four months. Emergency keywords are competitive but achievable within three to six months. The cumulative effect of optimising across all your services builds compounding traffic over six to twelve months."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
