-- 3. Property Maintenance × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'lead-capture',
  'Property maintenance companies serve the widest range of customer types in any trade: homeowners with one-off repairs, landlords with periodic maintenance needs, letting agents managing portfolios of properties, facilities managers overseeing commercial buildings, and housing associations with ongoing contract requirements. Each customer type has different urgency levels, different information needs, and different decision-making processes. A letting agent reporting a tenant emergency needs instant phone contact. A homeowner planning a bathroom renovation wants to describe their project and upload photos. A facilities manager evaluating contractors needs to request a capabilities presentation and references. Generic contact forms fail every one of these audiences. Our lead capture systems for property maintenance companies create distinct pathways for each customer type, capturing the specific information relevant to their enquiry and routing it to the appropriate response process. Emergency repairs trigger instant notification. Contract enquiries receive detailed proposals. Domestic projects get structured follow-up sequences that convert browsers into booked jobs.',
  'Property maintenance companies lose leads at two critical points: emergency callers who cannot reach someone instantly, and planned work enquiries that arrive with insufficient information for accurate quoting. Every emergency call that goes to voicemail is a customer who immediately calls your competitor. Every vague enquiry that requires a twenty-minute qualification phone call is time stolen from revenue-generating work. Effective lead capture solves both problems simultaneously.',
  'We build separate capture pathways for emergency reactive repairs, planned domestic projects, and commercial contract enquiries. Emergency visitors see click-to-call with live availability status. Domestic project forms capture property type, job scope, photos, and preferred timeline. Commercial enquiry forms capture portfolio size, current contractor situation, and required service disciplines.',
  '[{"title": "Emergency repair callers lost because they reach voicemail", "description": "When a letting agent calls about a burst pipe at a rental property and reaches your voicemail, they immediately call the next number on their list. Emergency property maintenance is the most time-sensitive lead type in the trades sector. Without instant contact capability and overflow routing, every missed emergency call is a lost customer and a damaged relationship."}, {"title": "Planned work enquiries arriving as vague messages requiring lengthy qualification", "description": "A message saying can you give me a quote for some work at my house tells you nothing about the trade required, the scope of work, property access, or timeline. You then spend twenty minutes on the phone extracting information that a structured form would capture automatically. Multiply this by ten enquiries per week and you are losing an entire afternoon to qualification calls."}, {"title": "No system for identifying and prioritising high-value contract opportunities", "description": "A letting agent managing fifty properties represents tens of thousands of pounds in annual maintenance revenue. But when their initial enquiry arrives through the same generic form as a request to fix a dripping tap, it receives the same response priority. Without lead scoring and identification, your highest-value opportunities are treated identically to your lowest-value ones."}]',
  '[{"title": "Multi-path capture system for every customer type", "description": "Emergency callers see prominent click-to-call buttons with live availability indicators and response time commitments. Homeowners complete project-specific forms with photo upload capability. Letting agents and property managers access dedicated enquiry forms that capture portfolio size, current maintenance arrangements, and required service disciplines. Each path delivers the right experience for the right audience."}, {"title": "Intelligent enquiry forms with trade-specific qualification", "description": "Multi-step forms that first identify the required trade discipline, then ask relevant follow-up questions for that specific service. A plumbing enquiry captures different information than a carpentry request. Each form collects the details you need to provide an accurate quote without requiring a follow-up phone call."}, {"title": "Lead scoring and automatic prioritisation of contract opportunities", "description": "Enquiries are automatically scored based on indicators of commercial value: portfolio size, multi-property requirements, contract interest, and commercial property flags. High-value leads from letting agents and property managers are flagged for priority response, ensuring your most profitable opportunities receive attention within minutes rather than days."}]',
  '[{"question": "How does the emergency lead capture work differently from standard enquiries?", "answer": "Emergency visitors see a high-contrast banner with a click-to-call number and your current availability status on every page. Outside normal hours, the system offers an urgent callback form that sends you an SMS alert. All emergency contact attempts are logged and trigger immediate notification so no urgent call goes unnoticed."}, {"question": "Can the system handle enquiries across all the different trades we offer?", "answer": "Yes. The initial form step identifies which trade discipline the enquiry relates to, then presents trade-specific follow-up questions. A plumbing enquiry asks about water systems and boiler age. An electrical enquiry captures consumer unit information. A decoration enquiry asks about room sizes and surface conditions. This ensures you receive the right details for every trade."}, {"question": "How do you identify letting agent leads versus domestic customer leads?", "answer": "The form system asks whether the enquiry is for an owned property, a rental property as a tenant, or a managed property as a landlord or agent. Letting agent and landlord responses trigger additional questions about portfolio size and maintenance contract interest. These leads are automatically scored higher and flagged for priority follow-up."}, {"question": "Can leads be routed to different team members based on trade type?", "answer": "Absolutely. Plumbing enquiries can route to your plumbing team, electrical work to your electricians, and contract enquiries to your commercial manager. Routing rules can also factor in urgency, location, and job value. This ensures every lead reaches the person best qualified to respond quickly and accurately."}]'
)
