-- 6. Property Maintenance × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'social-media-setup',
  'Property maintenance companies have a natural content advantage that most never exploit: the sheer variety of work you complete daily provides an endless stream of visual content across every trade discipline. A kitchen installation on Monday, an emergency boiler repair on Tuesday, a garden transformation on Wednesday, and a full house redecoration on Thursday gives you four pieces of compelling content in a single week. This variety keeps social feeds interesting and demonstrates the breadth of your capability in a way that a static website never can. When a letting agent sees your social feed showing professional plumbing, electrical, carpentry, and decorating work completed consistently over months, they gain confidence in your multi-trade capability that no sales pitch could replicate. Social media for property maintenance is not about chasing likes or building a following of people who will never need your services. It is about creating an active, visual portfolio that letting agents, property managers, and homeowners check before deciding to call you. Your social presence serves as rolling evidence that you are busy, competent across multiple trades, and trusted by other clients in their position.',
  'Letting agents and property managers check social media before recommending or contracting a maintenance company. An active feed showing consistent, professional work across multiple trade disciplines provides ongoing proof of capability that a brochure or website cannot match. Social proof from completed projects and genuine reviews removes the risk perception that prevents property professionals from switching to an unknown contractor.',
  'We create content frameworks leveraging the variety of work property maintenance companies complete daily. Before-and-after project posts, emergency repair responses demonstrating rapid callout capability, contract completion showcases, and seasonal maintenance tip content are all templated for easy capture on site and scheduled posting.',
  '[{"title": "Incredible daily content going completely uncaptured", "description": "You complete transformative work every single day across multiple trade disciplines: kitchen installations, bathroom renovations, garden clearances, full redecorations, and emergency repairs. Every one of these is potential social media content, yet most property maintenance companies never photograph their work. The most compelling evidence of your capability disappears the moment you leave site."}, {"title": "No social proof for letting agents evaluating your company", "description": "A letting agent considering a new maintenance contractor will check your online presence. An empty or abandoned social media profile raises doubts about whether you are still actively trading and performing quality work. Meanwhile, your competitor with weekly project posts and five-star reviews appears busy, professional, and proven."}, {"title": "Sporadic posting creating an unreliable impression", "description": "Posting five projects in one week then nothing for three months creates a pattern that mirrors the inconsistency letting agents fear most in a maintenance contractor. They need reliability and predictability. An inconsistent social presence suggests an inconsistent service, even if your actual work quality is excellent."}]',
  '[{"title": "Multi-trade content framework with daily capture workflow", "description": "A systematic approach to capturing content across every trade discipline. Quick photo checklists for engineers ensure before-and-after shots are taken on every job. Content is categorised by trade type and organised into a posting schedule that showcases your full range of capabilities every week."}, {"title": "Professional profiles targeting property professional audiences", "description": "Social media profiles set up to attract and impress letting agents, property managers, and commercial clients alongside domestic homeowners. LinkedIn presence targeting property professionals with case studies and contract capability content. Facebook and Instagram showcasing the visual quality of your work across all disciplines."}, {"title": "Automated review generation across all customer segments", "description": "Post-job review request sequences sent to every customer type. Letting agent testimonials highlight reliability, response times, and multi-trade capability. Domestic customer reviews emphasise quality, tidiness, and communication. Google Business Profile and Facebook reviews build a consistent stream of social proof that attracts new enquiries."}]',
  '[{"question": "What content should a property maintenance company post on social media?", "answer": "The most effective content includes before-and-after transformation shots from renovation and decoration projects, emergency repair response posts demonstrating your callout capability, completed contract work for recognisable local property brands, and seasonal maintenance tips. The variety of your work is your biggest content advantage."}, {"question": "Which social media platforms matter most for property maintenance?", "answer": "Facebook is essential for local community visibility and letting agent recommendations. Instagram provides a visual portfolio that property professionals browse before making decisions. LinkedIn is valuable for connecting with letting agents, property managers, and facilities managers. Google Business posts improve local search visibility across all customer types."}, {"question": "How do we get our engineers to take photos on every job?", "answer": "We create a simple three-photo checklist: before, during, and after. Engineers capture these on their phones at the start and end of each job. Photos are submitted through a simple process and batch-scheduled into social posts with professional captions. The time investment per job is under two minutes."}, {"question": "Can social media really help us win letting agent contracts?", "answer": "Absolutely. Letting agents increasingly check social media when evaluating maintenance contractors. A consistent feed showing quality work across multiple trades, positive reviews from other property professionals, and evidence of reliable emergency response provides exactly the reassurance they need to switch from their current contractor to your business."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
