-- 7. Property Maintenance × Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'digital-marketing',
  'Digital marketing for property maintenance companies must address two fundamentally different audiences with different channels, messaging, and conversion paths. Domestic homeowners find you through Google searches, local Facebook groups, and Checkatrade-style directories when something breaks or they plan a renovation. Letting agents, property managers, and commercial clients discover you through targeted outreach, LinkedIn, industry directories, and referral networks. A single digital marketing strategy cannot serve both audiences effectively. The homeowner who searches for handyman near me and the facilities manager searching for commercial maintenance contractor have entirely different needs, evaluate your business against different criteria, and convert through different journeys. Our digital marketing campaigns for property maintenance companies run parallel strategies: consumer-facing campaigns capture high-intent domestic searches and local community visibility, while business-to-business campaigns target property professionals through LinkedIn advertising, email marketing, and industry-specific content. Both campaigns run simultaneously, each optimised for its audience, creating a marketing engine that feeds your reactive domestic work and builds your contract pipeline in equal measure.',
  'Property maintenance companies that rely solely on word of mouth and Checkatrade listings hit a growth ceiling that only deliberate digital marketing can break through. The letting agents and property managers who represent your most valuable contracts are not browsing Checkatrade. They are searching LinkedIn, reading industry content, and evaluating your digital presence against competitors who are actively marketing to them. Without a business-to-business digital strategy, you are invisible to your highest-value prospects.',
  'We run parallel domestic and commercial campaigns from a single marketing system. Google Ads capture high-intent emergency and planned work searches from homeowners. LinkedIn campaigns and targeted email outreach reach letting agents and property managers. Retargeting keeps your brand visible to commercial prospects across their extended evaluation period.',
  '[{"title": "Marketing focused entirely on domestic work while contract opportunities go untargeted", "description": "Most property maintenance companies market exclusively to homeowners through Checkatrade, local Facebook ads, and Google searches. Meanwhile, letting agents managing hundreds of properties and facilities managers overseeing commercial buildings are never reached because they use entirely different channels. Your most profitable customer segment is completely ignored by your marketing."}, {"title": "No retargeting to nurture commercial prospects through longer decision cycles", "description": "A letting agent evaluating maintenance contractors does not make a decision after a single website visit. They research several companies over weeks or months, often waiting until their current contract expires. Without retargeting campaigns keeping your brand visible during this evaluation period, you are forgotten long before the decision is made."}, {"title": "Undifferentiated messaging failing to convert any audience effectively", "description": "A single marketing message about your property maintenance services fails to resonate with any specific audience. Homeowners want to know about rapid emergency response and fair pricing. Letting agents want to see contract capability, compliance credentials, and response time SLAs. When your marketing tries to say everything to everyone, it convinces nobody."}]',
  '[{"title": "Parallel domestic and commercial campaign architecture", "description": "Separate campaign structures for domestic and commercial audiences running simultaneously. Google Ads target high-intent domestic searches for emergency repairs and planned work. LinkedIn advertising and targeted email campaigns reach letting agents, property managers, and facilities managers. Each campaign uses audience-specific messaging, landing pages, and conversion goals."}, {"title": "Property professional retargeting and nurture sequences", "description": "Letting agents and property managers who visit your website are retargeted across LinkedIn, Google Display, and Facebook over a sustained period matching their typical evaluation timeline. Email nurture sequences deliver case studies, compliance capability information, and contract benefits over weeks, keeping your business front of mind until they are ready to switch contractors."}, {"title": "Seasonal campaign calendar aligned with maintenance demand patterns", "description": "Campaign budgets and messaging shift with seasonal demand. Winter campaigns emphasise emergency repair capability and boiler servicing. Spring campaigns target garden maintenance and exterior preparation. Summer focuses on renovation and redecoration projects. Autumn promotes boiler servicing and winterisation. This seasonal alignment ensures your marketing budget generates maximum return throughout the year."}]',
  '[{"question": "Should we market differently to domestic customers and letting agents?", "answer": "Absolutely. These audiences use different channels, respond to different messaging, and have different decision timelines. Domestic customers convert through Google search and local social media within days. Letting agents evaluate contractors over weeks through LinkedIn, industry content, and direct outreach. Running separate campaigns for each audience dramatically improves conversion rates for both."}, {"question": "How do you reach letting agents and property managers digitally?", "answer": "LinkedIn advertising targets property professionals by job title, company type, and location. Targeted email campaigns reach letting agent offices with case studies and capability presentations. Google Ads capture searches for terms like property maintenance contractor for letting agents. Industry directory listings place you where property professionals actively search for contractors."}, {"question": "How much should a property maintenance company spend on digital marketing?", "answer": "Budget depends on your growth targets and the split between domestic and commercial work. Domestic campaigns typically deliver strong returns from five hundred to fifteen hundred pounds monthly. Commercial campaigns targeting property professionals require smaller budgets but longer timelines. We recommend starting with a balanced allocation and adjusting based on which pipeline needs more fuel."}, {"question": "Can digital marketing help us win larger commercial maintenance contracts?", "answer": "Yes. Targeted LinkedIn campaigns, professional case study content, and retargeting sequences build familiarity and credibility with commercial decision-makers over their evaluation period. When a facilities manager is ready to review their maintenance contract, your business is already known, trusted, and top of mind because your marketing has maintained visibility throughout their decision cycle."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
