  faqs = EXCLUDED.faqs;

-- 8. Property Maintenance × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'workwear-print',
  'Property maintenance engineers enter people''s homes, commercial offices, and managed rental properties every day. Your team''s appearance at the door is the very first assessment every customer makes, and for letting agents and property managers who recommend you to their tenants, your engineers'' presentation reflects directly on their own professionalism. A property maintenance company with uniformed, identifiable engineers wearing branded workwear with photo ID badges communicates the organised, professional operation that wins and retains commercial contracts. Most property maintenance companies have an inconsistent approach to workwear: the office ordered polo shirts three years ago, half the team still wears them, the other half wears whatever they brought from home, and nobody has matching high-visibility vests on commercial sites. Printed materials are equally inconsistent, with quotes produced in different formats by different team members and job sheets varying by trade discipline. We supply coordinated workwear programmes and printed material suites that create a unified professional appearance across every trade discipline, every team member, and every customer-facing document your business produces.',
  'Letting agents evaluate property maintenance contractors partly on how engineers present themselves to tenants. A uniformed engineer with a branded ID badge at a rental property reinforces the agent''s decision to recommend your company. An unidentifiable person in casual clothing creates complaints and undermines the agent''s confidence. For commercial contracts, branded high-visibility workwear and PPE are often contractual requirements. Professional presentation is not optional; it is a condition of your most valuable relationships.',
  'We supply workwear programmes designed for multi-trade property maintenance. Core uniform items are consistent across all disciplines while trade-specific additions accommodate different working requirements. Seasonal layering options ensure branded appearance in all weather. Print materials follow the same brand standards across every document type.',
  '[{"title": "Inconsistent appearance across different trade teams", "description": "When your plumbers wear blue, your electricians wear black, and your decorators wear their own clothes, your property maintenance company looks like several unrelated businesses operating under one name. Letting agents who contract your company expect a unified, professional appearance from every engineer who attends their properties, regardless of trade discipline."}, {"title": "No ID badges creating security concerns at managed properties", "description": "Letting agents and property managers are responsible for tenant safety and increasingly require contractors to present identification. Property maintenance engineers without branded photo ID badges cause tenant complaints, access refusals, and management concerns. On commercial sites, identification is a non-negotiable access requirement."}, {"title": "Printed materials varying in quality and format between team members", "description": "Different team members producing quotes in different formats, using inconsistent pricing layouts, and presenting varying levels of professionalism in their documentation creates a fragmented customer experience. A letting agent receiving quotes from two of your engineers that look nothing alike questions your organisational capability."}]',
  '[{"title": "Unified workwear programme across all trade disciplines", "description": "Coordinated branded workwear including polo shirts, fleeces, softshell jackets, high-visibility vests, and trade-specific items like overalls and cargo trousers. Every team member, regardless of trade discipline, presents a consistent professional appearance. Seasonal layering options maintain branded visibility in all weather conditions."}, {"title": "Professional ID badge and PPE compliance system", "description": "Photo ID badges with company branding, employee name, DBS check reference, and trade qualification indicators. Branded hard hats, high-visibility jackets, and PPE for commercial site requirements. ID lanyards and badge holders in company colours. Your team meets the identification requirements of every client type from domestic homeowners to commercial facilities managers."}, {"title": "Complete printed material suite with brand consistency", "description": "Branded templates for quotations, job sheets, completion reports, invoices, and maintenance contract proposals. Business cards for every team member. Vehicle signage and magnetic door panels. A4 and A5 promotional leaflets targeting different customer segments. Every printed touchpoint maintains the same professional brand standard."}]',
  '[{"question": "Can we have the same uniform across plumbers, electricians, and decorators?", "answer": "Yes. We design a core uniform range that works across all trade disciplines. Polo shirts, fleeces, and outerwear are consistent for every team member. Trade-specific items like overalls, cargo trousers, and protective equipment are added as needed without breaking the unified brand appearance. The result is one company, one look."}, {"question": "Do you supply branded PPE for commercial site requirements?", "answer": "Absolutely. Branded hard hats, high-visibility jackets and vests, safety boots with embroidered logos, and protective eyewear are all available with your company branding. This ensures your team meets commercial site PPE requirements while maintaining brand visibility in environments where multiple contractors work alongside each other."}, {"question": "What printed materials does a property maintenance company need?", "answer": "At minimum: branded quotation templates, job completion sheets, invoices, and business cards. We also recommend A4 capability brochures for commercial contract tenders, vehicle signage, and promotional leaflets targeting different customer segments. The complete suite ensures every customer interaction reinforces your professional brand."}, {"question": "How do you handle new starters joining the team?", "answer": "We maintain stock of your core uniform items in standard sizes for immediate issue to new team members. Photo ID badges are produced and dispatched within days of receiving the employee''s photo and details. No new team member attends a customer site without the full branded uniform and identification."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Property Maintenance × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'ai-chatbots',
  'Property maintenance companies receive enquiries at all hours because emergencies do not respect business hours. A burst pipe at midnight, a boiler failure on a Sunday morning, and a broken window at a rental property on a bank holiday all generate urgent contact attempts. Beyond emergencies, letting agents managing large portfolios submit maintenance requests throughout the day and expect immediate acknowledgement. Homeowners planning renovation projects browse your website in the evenings when your office is closed. An AI chatbot for property maintenance handles all of these scenarios simultaneously. Emergency visitors are triaged instantly, with genuine emergencies escalated to your on-call engineer via SMS while non-urgent issues are logged for next-day response. Letting agents can report maintenance issues through a conversational interface that captures property address, tenant details, fault description, and access arrangements without waiting for office hours. Homeowners planning projects receive immediate guidance on your services, approximate timelines, and can book a survey appointment. Your chatbot becomes a twenty-four-hour front desk that never misses an enquiry, never puts a letting agent on hold, and never lets an emergency caller bounce to a competitor.',
  'Property maintenance enquiries peak outside office hours because emergencies are unpredictable and homeowners browse in the evening. Every after-hours enquiry that goes unanswered is a customer who calls your competitor. For letting agents, the inability to report urgent maintenance issues outside nine-to-five is a genuine frustration that drives them toward competitors offering twenty-four-hour reporting. An AI chatbot provides immediate response at any hour without the cost of staffing a night office.',
  'We build chatbots that understand the urgency spectrum of property maintenance. Emergency triage protocols distinguish genuine emergencies from routine requests, escalating real emergencies to on-call staff instantly. Letting agent workflows capture all the information your team needs to dispatch the right engineer. Planned work conversations qualify projects and book survey appointments.',
  '[{"title": "Emergency callers receiving no response outside office hours", "description": "A burst pipe or gas leak does not wait until Monday morning. When a tenant or homeowner contacts your business at ten pm with a genuine emergency and receives no response, they call the next company immediately. That lost emergency call also loses any future relationship with that customer, their landlord, and any properties they manage."}, {"title": "Letting agents unable to report maintenance issues outside nine-to-five", "description": "Letting agents manage properties across extended hours and cannot wait until your office opens to report maintenance issues from tenants. If they cannot log a repair request quickly and receive confirmation that it is being handled, they will switch to a maintenance contractor who offers more responsive communication."}, {"title": "Evening website visitors leaving without making contact", "description": "Homeowners researching property maintenance for renovation projects, bathroom refurbishments, or kitchen installations typically browse in the evening after work. When they visit your website at eight pm and find no way to get immediate answers to their questions, they move to the next company. These planned project leads are valuable and entirely recoverable with a chatbot."}]',
  '[{"title": "Emergency triage chatbot with on-call engineer escalation", "description": "The chatbot identifies genuine emergencies through a structured triage conversation: water leaks, gas smells, power failures, and security breaches are escalated immediately to your on-call engineer via SMS and phone alert. Non-urgent issues reported as emergencies are logged for priority next-day response. This ensures your on-call team is only disturbed for real emergencies while no genuine emergency goes unattended."}, {"title": "Letting agent maintenance reporting portal", "description": "A conversational interface where letting agents can report maintenance issues at any hour. The chatbot captures property address, tenant contact details, fault description, access arrangements, and urgency level. Reports are logged in your job management system and acknowledged immediately, giving the agent a reference number and expected response timeline."}, {"title": "Planned project qualification and survey booking", "description": "Evening visitors exploring renovation, refurbishment, or maintenance services are guided through a conversational qualification process. The chatbot identifies the service required, captures property details and project scope, and offers available survey appointment slots. These qualified leads are ready for follow-up when your office opens the next morning."}]',
  '[{"question": "Can the chatbot distinguish between a real emergency and a non-urgent repair reported as urgent?", "answer": "Yes. The triage protocol asks specific questions about the situation: is there water flowing uncontrollably, can you smell gas, has the power gone out completely, or is there a security breach. Based on the answers, genuine emergencies are escalated to your on-call team immediately, while non-urgent issues are logged for priority next-day response with appropriate messaging to the customer."}, {"question": "How does the chatbot work for letting agents reporting maintenance issues?", "answer": "The chatbot presents a streamlined reporting interface for property professionals. It captures the property address, tenant name and contact number, fault description, urgency level, and access arrangements. The report is logged in your system and the agent receives an immediate confirmation with a reference number and your committed response timeline."}, {"question": "Can the chatbot book survey appointments for renovation projects?", "answer": "Yes. The chatbot guides visitors through a project qualification conversation, identifies the required service, captures property details, and presents available survey slots from your calendar. Confirmed bookings are added to your schedule with all captured details attached, so your surveyor arrives prepared for the specific project type."}, {"question": "What happens if the chatbot cannot answer a question?", "answer": "The chatbot is designed to handle the most common enquiry types for property maintenance: emergencies, maintenance reporting, service information, and appointment booking. For questions outside its scope, it captures the visitor''s details and question, logs the enquiry for human follow-up, and provides an expected response time. No visitor leaves without their enquiry being recorded."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Property Maintenance × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'ai-content',
  'Property maintenance companies have the largest content opportunity in the trades sector because the breadth of services creates dozens of distinct content categories. Every trade discipline you offer generates its own set of guides, advice articles, seasonal content, and educational resources. Plumbing content covers boiler maintenance, pipe insulation, and water efficiency. Electrical content addresses safety testing, consumer unit upgrades, and EV charger considerations. Decorating content targets colour trends, surface preparation, and paint selection. Garden maintenance creates seasonal planting guides, lawn care advice, and outdoor living content. The challenge is that writing content across all these disciplines is practically impossible for a business owner already managing engineers, scheduling, and administration. AI-powered content creation solves this by producing technically accurate, SEO-optimised content across every service discipline your business covers. Each piece is tailored to the specific trade, targets relevant search terms, and demonstrates the breadth of expertise that differentiates a professional property maintenance company from a one-man handyman operation.',
  'Content marketing for property maintenance works because your audience actively searches for information before hiring. Homeowners research costs, processes, and timelines for renovation projects. Landlords search for compliance obligations and maintenance schedules. Letting agents look for contractor capability assessments. Without content addressing these searches, your website provides no value beyond a phone number, and Google has no reason to rank it above competitors who do provide helpful, comprehensive information.',
  'Our AI content system produces trade-specific content across every discipline your business covers. Each piece is written with the technical accuracy expected from qualified tradespeople, optimised for the search terms your customers actually use, and published on a consistent schedule that builds topical authority across all your service categories.',
  '[{"title": "Dozens of service pages with thin or no supporting content", "description": "A property maintenance website with thirty service listings and no supporting content for any of them provides Google with nothing to rank. Each service page competes against specialist websites with comprehensive guides, project examples, and advice content. Without depth behind your breadth, your multi-trade capability becomes an SEO weakness."}, {"title": "No capacity to write content across multiple trade disciplines", "description": "Writing authoritative content about plumbing, electrical, carpentry, decorating, roofing, and garden maintenance requires knowledge across all these trades and the time to produce it. Business owners managing multi-trade operations do not have twenty hours per month to write blog posts, and hiring specialist writers for each discipline is prohibitively expensive."}, {"title": "Missing seasonal content opportunities throughout the year", "description": "Property maintenance demand follows predictable seasonal patterns, and content published ahead of each season captures traffic as searches increase. Frozen pipe prevention content in November, garden preparation guides in February, exterior painting advice in April, and boiler servicing reminders in September all drive relevant traffic. Missing these windows means missing the traffic peaks."}]',
  '[{"title": "Multi-trade content production across every service discipline", "description": "AI-powered content creation produces technically accurate articles, guides, and advice content across every trade your business covers. Plumbing, electrical, carpentry, decorating, roofing, and garden maintenance each receive dedicated content streams targeting their specific search terms and customer questions."}, {"title": "Seasonal content calendar aligned with maintenance demand cycles", "description": "A twelve-month content plan publishing relevant articles ahead of each seasonal demand peak. Winter content targets emergency preparation and heating efficiency. Spring covers garden maintenance and exterior assessment. Summer focuses on renovation planning and decorating. Autumn publishes boiler servicing and weatherproofing guides. Content is ready before customers start searching."}, {"title": "Landlord and letting agent targeted content series", "description": "Dedicated content streams targeting property professionals with compliance guides, maintenance scheduling advice, cost management strategies, and contractor evaluation frameworks. This content attracts commercial search traffic, demonstrates your industry expertise, and positions your business as a knowledgeable partner rather than just a contractor."}]',
  '[{"question": "Can AI content be technically accurate across so many different trades?", "answer": "Yes. Our AI content system is configured with trade-specific technical knowledge and reviewed against current regulations and best practices for each discipline. Content about electrical testing references current regulations, plumbing content reflects current building standards, and decorating content uses appropriate trade terminology. Technical accuracy is verified before publication."}, {"question": "How much content can be produced each month for a property maintenance company?", "answer": "We typically produce eight to twelve pieces of content monthly for property maintenance companies, distributed across your service categories. This includes service page supporting content, seasonal advice articles, landlord-targeted guides, and project showcase descriptions. The exact volume is calibrated to your SEO strategy and the competitiveness of your target search terms."}, {"question": "Does the content target both domestic and commercial audiences?", "answer": "Yes. The content calendar includes streams for domestic homeowners searching for maintenance advice and renovation guidance alongside content targeting letting agents, landlords, and property managers with compliance information and maintenance strategy content. Each stream uses the language and addresses the concerns of its specific audience."}, {"question": "How does AI content help with SEO for a property maintenance company?", "answer": "Each piece of content targets specific search terms related to your services and publishes on a consistent schedule that signals to Google that your website is an active, authoritative resource. Over months, this builds topical authority across all your service categories, improving rankings for both the content pieces themselves and your core service pages."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 11. Property Maintenance × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'property-maintenance',
  'ai-automation',
  'Property maintenance companies operate in a uniquely complex environment where multiple trade disciplines, reactive emergency work, planned maintenance contracts, and diverse customer types create administrative demands that overwhelm manual processes. AI automation takes the business automation foundation and adds intelligent decision-making to the most complex operational challenges you face. Instead of simple rule-based workflows, AI automation learns from your operational patterns to optimise engineer dispatch based on skills, location, traffic conditions, and job complexity. It predicts maintenance failures before they occur by analysing service history patterns across your property portfolio. It automatically categorises and prioritises incoming maintenance requests from letting agents based on urgency, trade requirement, and contractual response commitments. The difference between standard automation and AI automation is the difference between a system that follows rules and a system that makes decisions. For property maintenance companies managing complex, multi-trade operations across large property portfolios, AI automation handles the operational complexity that would otherwise require additional management staff, enabling growth without proportional increases in overhead.',
  'Property maintenance companies hit a growth ceiling when operational complexity exceeds their management capacity. Managing fifty properties across multiple trade disciplines requires coordination that strains a small office team. Managing two hundred properties without AI-powered systems requires a back-office team whose cost erodes your margins. AI automation allows you to scale your property portfolio and job volume without proportionally scaling your administrative headcount.',
  'We implement AI automation that makes intelligent operational decisions for multi-trade property maintenance. Predictive maintenance algorithms identify properties likely to require intervention before emergency calls arrive. Smart dispatch considers trade skills, location, and job history. Automated reporting gives contract clients real-time visibility of maintenance activity across their portfolios.',
  '[{"title": "Engineer dispatch based on gut feeling rather than intelligent optimisation", "description": "When an emergency callout arrives and your office manager decides which engineer to send based on who they think is nearest or least busy, they are making a decision without real-time information. The engineer they choose may be thirty minutes further away than an alternative, or may lack the specific trade skills the job requires, resulting in a wasted first visit."}, {"title": "Reactive maintenance pattern with no predictive capability", "description": "Property maintenance is overwhelmingly reactive: something breaks, someone reports it, you fix it. But many breakdowns are predictable. A boiler that required three repairs last winter will likely fail again. A property with historic damp issues will need intervention every autumn. Without pattern analysis, you cannot offer proactive maintenance that prevents expensive emergencies."}, {"title": "Contract reporting consuming hours of manual data compilation", "description": "Letting agents and property managers on maintenance contracts require regular reporting: jobs completed, response times achieved, outstanding issues, and spend against budget. Compiling this data manually from job sheets and invoices takes hours per client per month and is prone to errors that undermine client confidence in your reporting accuracy."}]',
  '[{"title": "AI-optimised engineer dispatch across multiple trade disciplines", "description": "When a job arrives, AI evaluates available engineers by trade qualification, current location, travel time including real-time traffic, ongoing job completion estimates, and the specific requirements of the new job. The system dispatches the optimal engineer and provides route guidance, reducing response times and minimising wasted travel between jobs."}, {"title": "Predictive maintenance intelligence across property portfolios", "description": "AI analyses maintenance history across your entire property portfolio to identify patterns and predict likely failures. Properties with recurring issues receive proactive maintenance recommendations before emergencies occur. Letting agents receive predictive reports highlighting properties that need attention, positioning your company as a proactive partner rather than a reactive repair service."}, {"title": "Automated contract reporting with real-time client dashboards", "description": "Contract clients receive automated monthly reports compiled from live job data: response times, completion rates, spend analysis, and outstanding issues. Real-time dashboards allow letting agents and property managers to view maintenance activity across their portfolio at any time. Reporting that previously consumed hours is generated automatically and delivered on schedule."}]',
  '[{"question": "How does AI dispatch improve on our current system?", "answer": "AI dispatch considers factors no human coordinator can process simultaneously: real-time engineer locations, traffic conditions, remaining time on current jobs, trade qualifications, property access requirements, and historical job complexity at specific addresses. The result is faster response times, fewer wasted journeys, and better matching of engineer skills to job requirements."}, {"question": "Can AI really predict when a property will need maintenance?", "answer": "AI analyses patterns in your maintenance history that humans cannot easily detect. A boiler with escalating repair frequency, a property with seasonal damp issues, or plumbing systems approaching known failure ages all generate predictive indicators. The system flags at-risk properties and recommends proactive maintenance, reducing emergency callouts and delighting contract clients."}, {"question": "How does the automated reporting work for letting agent contracts?", "answer": "The system compiles job data in real-time as work is completed. Monthly reports are generated automatically showing jobs completed, average response times, SLA compliance rates, spend against budget, and outstanding issues. Reports are branded with your company identity and delivered to each client on their preferred schedule without any manual compilation."}, {"question": "What is the difference between standard business automation and AI automation?", "answer": "Standard automation follows predetermined rules: if a job is completed, send an invoice. AI automation makes intelligent decisions: which engineer should be dispatched based on multiple dynamic factors, which properties are likely to need maintenance next month, and how to optimise your schedule across competing priorities. AI adds intelligence to the automation foundation."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;
